#!/bin/bash
set -e
cd "$(dirname "$0")"

mkdir -p 'app/guide/taishoku-daikou-ryoukin-souba'
python3 -c "import base64; open('app/guide/taishoku-daikou-ryoukin-souba/page.tsx', 'wb').write(base64.b64decode(''))"
echo '✅ app/guide/taishoku-daikou-ryoukin-souba/page.tsx'

mkdir -p 'app/guide/kyuuyo-keisan-zangyou-houhou'
python3 -c "import base64; open('app/guide/kyuuyo-keisan-zangyou-houhou/page.tsx', 'wb').write(base64.b64decode(''))"
echo '✅ app/guide/kyuuyo-keisan-zangyou-houhou/page.tsx'

mkdir -p 'scripts'
python3 -c "import base64; open('scripts/generate-article.mjs', 'wb').write(base64.b64decode(''))"
echo '✅ scripts/generate-article.mjs'

git add -A
git commit -m 'fix: remove markdown code fences from generated TSX files, prevent future occurrences'
git push origin main
echo '🚀 Push完了！Vercelビルド修正されます'